CREATE TYPE "Role" AS ENUM ('USER','MODERATOR','ADMIN'); CREATE TYPE "VerificationStatus" AS ENUM ('VERIFIED','PROBABLE','TO_REVIEW'); CREATE TYPE "SessionStatus" AS ENUM ('OPEN','FULL','CANCELLED','COMPLETED'); CREATE TYPE "ParticipantStatus" AS ENUM ('JOINED','WAITLIST','LEFT','REMOVED');
CREATE TABLE "Platform" ("id" TEXT PRIMARY KEY,"name" TEXT NOT NULL,"slug" TEXT UNIQUE NOT NULL,"manufacturer" TEXT,"active" BOOLEAN NOT NULL DEFAULT true,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "Game" ("id" TEXT PRIMARY KEY,"platformId" TEXT NOT NULL REFERENCES "Platform"("id"),"title" TEXT NOT NULL,"sortTitle" TEXT NOT NULL,"slug" TEXT NOT NULL,"aliases" JSONB NOT NULL DEFAULT '[]',"region" TEXT,"releaseYear" INTEGER,"description" TEXT,"genres" JSONB NOT NULL DEFAULT '[]',"playerMin" INTEGER,"playerMax" INTEGER,"simultaneous" BOOLEAN,"alternating" BOOLEAN,"coop" BOOLEAN,"versus" BOOLEAN,"dropIn" BOOLEAN,"splitScreen" BOOLEAN,"multitap" BOOLEAN,"teamPlayerCompatible" BOOLEAN,"verificationStatus" "VerificationStatus" NOT NULL DEFAULT 'TO_REVIEW',"sourceConfidence" TEXT,"coverWebpPath" TEXT,"coverJpegPath" TEXT,"coverBlurData" TEXT,"coverSourceName" TEXT,"coverSourceUrl" TEXT,"published" BOOLEAN NOT NULL DEFAULT true,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,UNIQUE("platformId","slug"));
CREATE TABLE "User" ("id" TEXT PRIMARY KEY,"email" TEXT UNIQUE NOT NULL,"username" TEXT UNIQUE NOT NULL,"displayName" TEXT NOT NULL,"passwordHash" TEXT NOT NULL,"city" TEXT,"timezone" TEXT NOT NULL DEFAULT 'Europe/Paris',"role" "Role" NOT NULL DEFAULT 'USER',"status" TEXT NOT NULL DEFAULT 'ACTIVE',"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
